// ─── GEOMETRY HELPERS ─────────────────────────────────────────────

function polygonToPath(
  points: Array<{ x: number; y: number }>,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  edgeCurves?: any
): string {
  if (!points || !points.length) return '';
  let d = `M ${points[0].x} ${points[0].y}`;
  for (let i = 0; i < points.length; i++) {
    const next = points[(i + 1) % points.length];
    const curve = edgeCurves ? edgeCurves[i] : null;
    if (curve) {
      d += ` C ${curve.cp1.x} ${curve.cp1.y} ${curve.cp2.x} ${curve.cp2.y} ${next.x} ${next.y}`;
    } else {
      d += ` L ${next.x} ${next.y}`;
    }
  }
  return d + ' Z';
}

function arcPath(
  cx: number,
  cy: number,
  innerR: number,
  outerR: number,
  sa: number,
  ea: number
): string {
  const largeArc = Math.abs(ea - sa) > Math.PI ? 1 : 0;
  const sweep = ea > sa ? 1 : 0;
  const x1 = cx + Math.cos(sa) * outerR;
  const y1 = cy + Math.sin(sa) * outerR;
  const x2 = cx + Math.cos(ea) * outerR;
  const y2 = cy + Math.sin(ea) * outerR;
  const x3 = cx + Math.cos(ea) * innerR;
  const y3 = cy + Math.sin(ea) * innerR;
  const x4 = cx + Math.cos(sa) * innerR;
  const y4 = cy + Math.sin(sa) * innerR;
  return [
    `M ${x1} ${y1}`,
    `A ${outerR} ${outerR} 0 ${largeArc} ${sweep} ${x2} ${y2}`,
    `L ${x3} ${y3}`,
    `A ${innerR} ${innerR} 0 ${largeArc} ${1 - sweep} ${x4} ${y4}`,
    'Z',
  ].join(' ');
}

function patternDefs(
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  pattern: any,
  sectionId: string
): { id: string; markup: string } | null {
  if (!pattern || pattern.type === 'none') return null;
  const id = `pat-${sectionId}`;
  const color = pattern.color || '#ffffff';
  const size = Math.max(2, pattern.size || 4);
  const spacing = Math.max(size, pattern.spacing || 16);
  const opacity = pattern.opacity != null ? pattern.opacity : 0.35;
  let body = '';
  if (pattern.type === 'dots') {
    body = `<circle cx="${spacing / 2}" cy="${spacing / 2}" r="${size / 2}" fill="${color}" fill-opacity="${opacity}" />`;
  } else if (pattern.type === 'grid') {
    body = `<path d="M ${spacing} 0 L 0 0 0 ${spacing}" fill="none" stroke="${color}" stroke-opacity="${opacity}" stroke-width="${Math.max(0.5, size / 4)}" />`;
  } else if (pattern.type === 'stripes') {
    body = `<rect width="${Math.max(2, size)}" height="${spacing}" fill="${color}" fill-opacity="${opacity}" />`;
  } else if (pattern.type === 'custom') {
    body = pattern.customSvg || '';
  }
  const markup = `<pattern id="${id}" x="0" y="0" width="${spacing}" height="${spacing}" patternUnits="userSpaceOnUse">${body}</pattern>`;
  return { id, markup };
}

// ─── SPATIAL GRID (per section) ────────────────────────────────────
// Enables O(cellsTouched) rect queries for viewport culling and O(1)-ish
// point queries for canvas-mode hit-testing, replacing linear O(seats)
// scans that used to run on every pan / click.

interface SeatRef {
  seat: AnySeat;
  sectionId: string;
  worldX: number;
  worldY: number;
  width: number;
  height: number;
}

class SectionSeatGrid {
  readonly sectionId: string;
  readonly offsetX: number;
  readonly offsetY: number;
  readonly cellSize: number;
  readonly cols: number;
  readonly rows: number;
  readonly cells: SeatRef[][];
  readonly refs: SeatRef[];

  constructor(section: AnySection) {
    this.sectionId = section.id;
    const seats = section.seats || [];
    const refs: SeatRef[] = new Array(seats.length);
    let avgSize = 24;
    if (seats.length) {
      let sumSize = 0;
      for (let i = 0; i < seats.length; i++) {
        const s = seats[i];
        const wx = section.bounds.x + s.bounds.x;
        const wy = section.bounds.y + s.bounds.y;
        refs[i] = {
          seat: s,
          sectionId: section.id,
          worldX: wx,
          worldY: wy,
          width: s.bounds.width,
          height: s.bounds.height,
        };
        sumSize += Math.min(s.bounds.width, s.bounds.height);
      }
      avgSize = sumSize / seats.length;
    }
    this.refs = refs;
    if (refs.length === 0) {
      this.offsetX = section.bounds.x;
      this.offsetY = section.bounds.y;
      this.cellSize = 64;
      this.cols = 1;
      this.rows = 1;
      this.cells = [[]];
      return;
    }
    // Cells a bit bigger than typical seats so neighbourhoods share a bucket.
    this.cellSize = Math.max(16, avgSize * 4);
    let minX = Infinity;
    let minY = Infinity;
    let maxX = -Infinity;
    let maxY = -Infinity;
    for (let i = 0; i < refs.length; i++) {
      const r = refs[i];
      if (r.worldX < minX) minX = r.worldX;
      if (r.worldY < minY) minY = r.worldY;
      if (r.worldX + r.width > maxX) maxX = r.worldX + r.width;
      if (r.worldY + r.height > maxY) maxY = r.worldY + r.height;
    }
    this.offsetX = minX;
    this.offsetY = minY;
    this.cols = Math.max(1, Math.ceil((maxX - minX) / this.cellSize));
    this.rows = Math.max(1, Math.ceil((maxY - minY) / this.cellSize));
    const total = this.cols * this.rows;
    const cells: SeatRef[][] = new Array(total);
    for (let i = 0; i < total; i++) cells[i] = [];
    for (let i = 0; i < refs.length; i++) {
      const r = refs[i];
      const cx = Math.max(
        0,
        Math.min(this.cols - 1, Math.floor((r.worldX - this.offsetX) / this.cellSize))
      );
      const cy = Math.max(
        0,
        Math.min(this.rows - 1, Math.floor((r.worldY - this.offsetY) / this.cellSize))
      );
      cells[cy * this.cols + cx].push(r);
    }
    this.cells = cells;
  }

  queryRect(rect: Rect, out: SeatRef[]): void {
    if (this.refs.length === 0) return;
    const rx2 = rect.x + rect.width;
    const ry2 = rect.y + rect.height;
    let x1 = Math.floor((rect.x - this.offsetX) / this.cellSize);
    let y1 = Math.floor((rect.y - this.offsetY) / this.cellSize);
    let x2 = Math.floor((rx2 - this.offsetX) / this.cellSize);
    let y2 = Math.floor((ry2 - this.offsetY) / this.cellSize);
    if (x1 < 0) x1 = 0;
    if (y1 < 0) y1 = 0;
    if (x2 >= this.cols) x2 = this.cols - 1;
    if (y2 >= this.rows) y2 = this.rows - 1;
    if (x1 > x2 || y1 > y2) return;
    for (let cy = y1; cy <= y2; cy++) {
      const row = cy * this.cols;
      for (let cx = x1; cx <= x2; cx++) {
        const bucket = this.cells[row + cx];
        for (let k = 0; k < bucket.length; k++) {
          const r = bucket[k];
          if (
            r.worldX < rx2 &&
            r.worldX + r.width > rect.x &&
            r.worldY < ry2 &&
            r.worldY + r.height > rect.y
          ) {
            out.push(r);
          }
        }
      }
    }
  }

  queryPoint(x: number, y: number): SeatRef | null {
    if (this.refs.length === 0) return null;
    const cx = Math.floor((x - this.offsetX) / this.cellSize);
    const cy = Math.floor((y - this.offsetY) / this.cellSize);
    if (cx < 0 || cy < 0 || cx >= this.cols || cy >= this.rows) return null;
    const bucket = this.cells[cy * this.cols + cx];
    for (let k = 0; k < bucket.length; k++) {
      const r = bucket[k];
      if (x >= r.worldX && x <= r.worldX + r.width && y >= r.worldY && y <= r.worldY + r.height) {
        return r;
      }
    }
    return null;
  }
}

// ─── TREE HELPERS / INDICES ───────────────────────────────────────

interface SectionIndexEntry {
  section: AnySection;
  parents: string[];
}
interface SeatIndexEntry {
  seat: AnySeat;
  section: AnySection;
  parents: string[];
}
interface VenueIndices {
  sectionIndex: Map<string, SectionIndexEntry>;
  seatIndex: Map<string, SeatIndexEntry>;
  sectionGrids: Map<string, SectionSeatGrid>;
  medianSeatSize: number;
}

function buildIndices(sections: AnySection[]): VenueIndices {
  const sectionIndex = new Map<string, SectionIndexEntry>();
  const seatIndex = new Map<string, SeatIndexEntry>();
  const sectionGrids = new Map<string, SectionSeatGrid>();
  const sizes: number[] = [];
  const walk = (list: AnySection[], parents: string[]) => {
    for (const s of list) {
      sectionIndex.set(s.id, { section: s, parents });
      const isContainer = s.children && s.children.length > 0;
      if (!isContainer && s.seats && s.seats.length) {
        for (const seat of s.seats) {
          seatIndex.set(seat.id, { seat, section: s, parents });
          sizes.push(Math.min(seat.bounds.width, seat.bounds.height));
        }
        sectionGrids.set(s.id, new SectionSeatGrid(s));
      }
      if (isContainer) walk(s.children, [...parents, s.id]);
    }
  };
  walk(sections, []);
  let medianSeatSize = 24;
  if (sizes.length > 0) {
    sizes.sort((a, b) => a - b);
    medianSeatSize = sizes[Math.floor(sizes.length / 2)] || 24;
  }
  return { sectionIndex, seatIndex, sectionGrids, medianSeatSize };
}

function getVisibleSections(
  sections: AnySection[],
  drillStack: string[]
): AnySection[] {
  if (!drillStack.length) return sections;
  let pool: AnySection[] = sections;
  for (const id of drillStack) {
    const found = pool.find((s: AnySection) => s.id === id);
    if (!found || !found.children) return [];
    pool = found.children;
  }
  return pool;
}

