// ─── SEAT NODE (DOM mode only) ────────────────────────────────────
// No per-seat event handlers — click / hover / keyboard are all
// handled by the delegated listener at the viewport root.

interface SeatNodeProps {
  seat: AnySeat;
  sectionName: string;
  sectionCurrency: string;
  sectionPrice: number;
  icon: string;
  customSeatIconSvg?: string;
  isSelected: boolean;
  state: SeatState;
}

function iconSymbolId(icon: string): string {
  switch (icon) {
    case 'chair':
      return 'sm-chair';
    case 'chair-simple':
      return 'sm-chair-simple';
    case 'circle':
      return 'sm-circle';
    case 'rounded':
      return 'sm-rounded';
    case 'square':
      return 'sm-square';
    default:
      return 'sm-rounded';
  }
}

function stateColor(state: SeatState, isSelected: boolean): string {
  if (isSelected) return SEAT_CONFIG.colors.selected;
  if (state === 'reserved') return SEAT_CONFIG.colors.reserved;
  if (state === 'disabled') return SEAT_CONFIG.colors.disabled;
  return SEAT_CONFIG.colors.available;
}

const SeatNode = React.memo(function SeatNode(props: SeatNodeProps) {
  const {
    seat,
    sectionName,
    sectionCurrency,
    sectionPrice,
    icon,
    customSeatIconSvg,
    isSelected,
    state,
  } = props;

  const isInteractable = state === 'available';
  const color = stateColor(state, isSelected);
  const size = Math.min(seat.bounds.width, seat.bounds.height);
  const badgeSize = Math.max(10, size * 0.35);

  const wrapperStyle: React.CSSProperties = {
    left: seat.bounds.x,
    top: seat.bounds.y,
    width: seat.bounds.width,
    height: seat.bounds.height,
    color,
    borderRadius: icon === 'circle' ? '50%' : SEAT_CONFIG.layout.seatBorderRadius,
  };

  return (
    <div
      className="sm-seat"
      role="button"
      aria-label={`${sectionName} ${seat.label} ${state}${seat.accessible ? ' accessible' : ''}`}
      aria-pressed={isSelected}
      aria-disabled={!isInteractable}
      data-seat-id={seat.id}
      data-interactable={isInteractable ? '1' : '0'}
      data-selected={isSelected ? '1' : '0'}
      tabIndex={isInteractable ? 0 : -1}
      title={`${seat.label} — ${sectionName}${seat.accessible ? ' — accessible' : ''} — ${sectionCurrency}${sectionPrice}`}
      style={wrapperStyle}
    >
      {icon === 'custom' && customSeatIconSvg ? (
        <div
          className="sm-seat-svg"
          style={{ color }}
          dangerouslySetInnerHTML={{ __html: customSeatIconSvg }}
        />
      ) : (
        <svg
          className="sm-seat-svg"
          viewBox="0 0 24 24"
          preserveAspectRatio="xMidYMid meet"
          focusable="false"
          aria-hidden="true"
        >
          <use href={`#${iconSymbolId(icon)}`} />
        </svg>
      )}
      {seat.accessible && (
        <div
          className="sm-seat-badge"
          style={{ width: badgeSize, height: badgeSize }}
        >
          <svg
            width={Math.max(8, size * 0.28)}
            height={Math.max(8, size * 0.28)}
            viewBox="0 0 24 24"
            focusable="false"
            aria-hidden="true"
          >
            <use href="#sm-wheel" />
          </svg>
        </div>
      )}
    </div>
  );
});

// ─── SECTION RENDER (memoized) ────────────────────────────────────
// Renders section fill / stroke / pattern / label, plus its seats
// when the parent passes any (DOM mode). In canvas mode, `seatsToRender`
// is empty and the canvas layer paints the seat sprites instead.

interface SectionRenderProps {
  section: AnySection;
  seatsToRender: AnySeat[];
  selectedSet: ReadonlySet<string>;
  seatStates: Record<string, SeatState>;
}

const EMPTY_SEATS: AnySeat[] = [];

const SectionRender = React.memo(function SectionRender(props: SectionRenderProps) {
  const { section, seatsToRender, selectedSet, seatStates } = props;

  const icon = section.seatIcon || SEAT_CONFIG.layout.seatIcon;
  const isPolygon = section.type === 'polygon' && section.points && section.points.length >= 3;
  const isArc = section.type === 'arc' && section.arc;
  const isContainer = section.children && section.children.length > 0;
  const hasSeats = !isContainer && section.seats && section.seats.length > 0;
  const pattern = useMemo(
    () => patternDefs(section.pattern, section.id),
    [section.pattern, section.id]
  );
  const interactions = section.interactions || {};
  const clickAction: string =
    interactions.clickAction ||
    (isContainer ? SEAT_CONFIG.interaction.defaultContainerClick : 'select');
  const isSectionClickable =
    isContainer || clickAction === 'url' || clickAction === 'event';
  const title =
    interactions.tooltip ||
    (isContainer ? `${section.name} — ${section.children.length} sub-sections` : section.name);

  const cornerRadius =
    section.cornerRadius != null ? section.cornerRadius : SEAT_CONFIG.layout.sectionBorderRadius;

  const polyPath = useMemo(
    () => (isPolygon ? polygonToPath(section.points, section.edgeCurves) : ''),
    [isPolygon, section.points, section.edgeCurves]
  );
  const arcD = useMemo(
    () =>
      isArc
        ? arcPath(
            section.bounds.width / 2,
            section.bounds.height / 2,
            section.arc.innerRadius,
            section.arc.outerRadius,
            section.arc.startAngle,
            section.arc.endAngle
          )
        : '',
    [
      isArc,
      section.bounds.width,
      section.bounds.height,
      section.arc?.innerRadius,
      section.arc?.outerRadius,
      section.arc?.startAngle,
      section.arc?.endAngle,
    ]
  );

  const wrapperStyle: React.CSSProperties = {
    position: 'absolute',
    left: section.bounds.x,
    top: section.bounds.y,
    width: section.bounds.width,
    height: section.bounds.height,
    transform: section.rotation ? `rotate(${section.rotation}deg)` : undefined,
    transformOrigin: 'center center',
    opacity: section.opacity,
    zIndex: section.zIndex,
    cursor: isSectionClickable ? 'pointer' : 'default',
    contain: 'layout paint style',
  };

  return (
    <div
      title={title}
      data-section-id={section.id}
      data-section-clickable={isSectionClickable ? '1' : '0'}
      data-section-action={clickAction}
      style={wrapperStyle}
    >
      {isPolygon ? (
        <svg
          width={section.bounds.width}
          height={section.bounds.height}
          viewBox={`0 0 ${section.bounds.width} ${section.bounds.height}`}
          preserveAspectRatio="none"
          style={{ position: 'absolute', inset: 0, pointerEvents: 'none' }}
        >
          {pattern && <defs dangerouslySetInnerHTML={{ __html: pattern.markup }} />}
          <path
            d={polyPath}
            fill={section.fill}
            stroke={section.stroke}
            strokeWidth={section.strokeWidth}
          />
          {pattern && <path d={polyPath} fill={`url(#${pattern.id})`} />}
        </svg>
      ) : isArc ? (
        <svg
          width={section.bounds.width}
          height={section.bounds.height}
          viewBox={`0 0 ${section.bounds.width} ${section.bounds.height}`}
          preserveAspectRatio="none"
          style={{ position: 'absolute', inset: 0, pointerEvents: 'none' }}
        >
          {pattern && <defs dangerouslySetInnerHTML={{ __html: pattern.markup }} />}
          <path
            d={arcD}
            fill={section.fill}
            stroke={section.stroke}
            strokeWidth={section.strokeWidth}
          />
          {pattern && <path d={arcD} fill={`url(#${pattern.id})`} />}
        </svg>
      ) : (
        <div
          style={{
            position: 'absolute',
            inset: 0,
            background: section.fill,
            border: `${section.strokeWidth}px solid ${section.stroke}`,
            borderRadius:
              section.type === 'circle' || section.type === 'ellipse' ? '50%' : cornerRadius,
            overflow: 'hidden',
            pointerEvents: 'none',
          }}
        >
          {pattern && (
            <svg
              style={{ position: 'absolute', inset: 0, width: '100%', height: '100%' }}
              preserveAspectRatio="none"
            >
              <defs dangerouslySetInnerHTML={{ __html: pattern.markup }} />
              <rect width="100%" height="100%" fill={`url(#${pattern.id})`} />
            </svg>
          )}
        </div>
      )}

      {isContainer && <div style={BADGE_CONTAINER_STYLE}>{section.children.length}</div>}

      {SEAT_CONFIG.layout.showSectionLabels && section.labelVisible && (
        <div
          style={{
            position: 'absolute',
            left: 0,
            right: 0,
            top: hasSeats ? -18 : '50%',
            transform: hasSeats ? undefined : 'translateY(-50%)',
            textAlign: 'center',
            color: SEAT_CONFIG.colors.sectionLabel,
            textShadow: '0 1px 3px rgba(0,0,0,0.85)',
            fontSize: Math.max(10, Math.min(16, section.bounds.width / 15)),
            fontWeight: 600,
            letterSpacing: 0.3,
            pointerEvents: 'none',
          }}
        >
          {section.name}
          {SEAT_CONFIG.layout.showPriceBadges && section.price > 0 && (
            <span style={{ marginLeft: 8, opacity: 0.75, fontWeight: 400 }}>
              {section.currency}
              {section.price}
            </span>
          )}
        </div>
      )}

      {hasSeats &&
        seatsToRender.length > 0 &&
        seatsToRender.map((seat: AnySeat) => {
          const state = (seatStates[seat.id] ?? seat.state) as SeatState;
          return (
            <SeatNode
              key={seat.id}
              seat={seat}
              sectionName={section.name}
              sectionCurrency={section.currency}
              sectionPrice={section.price}
              icon={icon}
              customSeatIconSvg={section.customSeatIcon?.svg}
              isSelected={selectedSet.has(seat.id)}
              state={state}
            />
          );
        })}
    </div>
  );
});

// ─── BREADCRUMB / CONTROLS / LEGEND ──────────────────────────────

const Breadcrumb = React.memo(function Breadcrumb({
  venueName,
  sections,
  onRoot,
  onUp,
}: {
  venueName: string;
  sections: AnySection[];
  onRoot: () => void;
  onUp: () => void;
}) {
  return (
    <div style={BREADCRUMB_STYLE}>
      <button onClick={onRoot} style={BREADCRUMB_ROOT_BTN_STYLE}>
        {venueName}
      </button>
      {sections.map((s, i) => (
        <React.Fragment key={s.id}>
          <span style={{ opacity: 0.5 }}>›</span>
          <span
            style={{
              padding: '2px 8px',
              borderRadius: 999,
              background:
                i === sections.length - 1 ? SEAT_CONFIG.colors.breadcrumbActive : 'transparent',
              fontWeight: i === sections.length - 1 ? 600 : 400,
            }}
          >
            {s.name}
          </span>
        </React.Fragment>
      ))}
      <button onClick={onUp} style={BREADCRUMB_UP_BTN_STYLE}>
        ← Back
      </button>
    </div>
  );
});

const Controls = React.memo(function Controls({
  onZoomIn,
  onZoomOut,
  onFit,
  zoom,
}: {
  onZoomIn: () => void;
  onZoomOut: () => void;
  onFit: () => void;
  zoom: number;
}) {
  return (
    <div style={CONTROLS_WRAPPER_STYLE}>
      <button type="button" onClick={onZoomOut} style={ctrlBtnStyle} aria-label="Zoom out">
        −
      </button>
      <div style={CONTROLS_ZOOM_LABEL_STYLE}>{Math.round(zoom * 100)}%</div>
      <button type="button" onClick={onZoomIn} style={ctrlBtnStyle} aria-label="Zoom in">
        +
      </button>
      <button type="button" onClick={onFit} style={ctrlBtnStyle} aria-label="Fit to view">
        ⊡
      </button>
    </div>
  );
});

const Legend = React.memo(function Legend({
  selectedCount,
  maxSelectable,
}: {
  selectedCount: number;
  maxSelectable: number;
}) {
  const items = [
    { color: SEAT_CONFIG.colors.available, label: 'Available' },
    { color: SEAT_CONFIG.colors.selected, label: 'Selected' },
    { color: SEAT_CONFIG.colors.reserved, label: 'Reserved' },
    { color: SEAT_CONFIG.colors.disabled, label: 'Unavailable' },
  ];
  return (
    <div style={LEGEND_STYLE}>
      {items.map((item) => (
        <span key={item.label} style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
          <span
            style={{
              width: 10,
              height: 10,
              borderRadius: '50%',
              background: item.color,
            }}
          />
          {item.label}
        </span>
      ))}
      <span style={{ marginLeft: 8, opacity: 0.7 }}>
        {selectedCount}
        {Number.isFinite(maxSelectable) ? ` / ${maxSelectable}` : ''} selected
      </span>
    </div>
  );
});

// ─── MAIN COMPONENT ──────────────────────────────────────────────

function SeatMapRuntime(props: SeatMapRuntimeProps) {
  const {
    venueData,
    initialSeatStates,
    onSeatSelect,
    onSelectionChange,
    onDrillIn,
    onDrillOut,
    initialDrillPath,
    readOnly = false,
    maxSelectable = Infinity,
    className,
    style,
  } = props;

  const venue = venueData.venue;
  const allSections: AnySection[] = venueData.sections;
  const stage = 'stage' in venueData ? venueData.stage : undefined;

  const indices = useMemo(() => buildIndices(allSections), [allSections]);
  const { sectionIndex, seatIndex, sectionGrids, medianSeatSize } = indices;

  const [seatStates, setSeatStates] = useState<Record<string, SeatState>>(() => ({
    ...(initialSeatStates ?? {}),
  }));
  useEffect(() => {
    if (initialSeatStates) setSeatStates({ ...initialSeatStates });
  }, [initialSeatStates]);

  const [selected, setSelected] = useState<string[]>([]);
  const selectedSet = useMemo(() => new Set(selected), [selected]);

  const [drillStack, setDrillStack] = useState<string[]>(initialDrillPath ?? []);

  const visibleSections = useMemo(
    () => getVisibleSections(allSections, drillStack),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [allSections, drillStack]
  );
  const sortedVisibleSections = useMemo(
    () => [...visibleSections].sort((a: AnySection, b: AnySection) => a.zIndex - b.zIndex),
    [visibleSections]
  );

  const [scale, setScale] = useState(1);
  const [tx, setTx] = useState(0);
  const [ty, setTy] = useState(0);
  const viewportRef = useRef<HTMLDivElement>(null);
  const baseCanvasRef = useRef<HTMLCanvasElement>(null);
  const overlayCanvasRef = useRef<HTMLCanvasElement>(null);
  const panState = useRef<{ startX: number; startY: number; tx: number; ty: number } | null>(null);
  const drillAnim = useRef<number | null>(null);

  const [marquee, setMarquee] = useState<null | { x1: number; y1: number; x2: number; y2: number }>(
    null
  );
  const marqueeRef = useRef(false);
  const marqueeStartedFromEmpty = useRef(false);

  const [containerSize, setContainerSize] = useState<{ width: number; height: number }>({
    width: 0,
    height: 0,
  });

  useLayoutEffect(() => {
    const el = viewportRef.current;
    if (!el) return;
    const update = () => {
      const r = el.getBoundingClientRect();
      setContainerSize((prev) =>
        prev.width === r.width && prev.height === r.height
          ? prev
          : { width: r.width, height: r.height }
      );
    };
    update();
    const ro = new ResizeObserver(update);
    ro.observe(el);
    return () => ro.disconnect();
  }, []);

  // ─── Pan/zoom refs for stable closures ──────────────────────────
  const scaleRef = useRef(scale);
  const txRef = useRef(tx);
  const tyRef = useRef(ty);
  scaleRef.current = scale;
  txRef.current = tx;
  tyRef.current = ty;

  const computeFit = useCallback(
    (bounds: { x: number; y: number; width: number; height: number }) => {
      const el = viewportRef.current;
      if (!el) return { scale: 1, tx: 0, ty: 0 };
      const rect = el.getBoundingClientRect();
      const sx = (rect.width - 40) / bounds.width;
      const sy = (rect.height - 40) / bounds.height;
      const s = Math.max(
        SEAT_CONFIG.interaction.minZoom,
        Math.min(sx, sy, SEAT_CONFIG.interaction.maxZoom)
      );
      return {
        scale: s,
        tx: (rect.width - bounds.width * s) / 2 - bounds.x * s,
        ty: (rect.height - bounds.height * s) / 2 - bounds.y * s,
      };
    },
    []
  );

  const animateToBounds = useCallback(
    (bounds: { x: number; y: number; width: number; height: number }) => {
      if (drillAnim.current) cancelAnimationFrame(drillAnim.current);
      const target = computeFit(bounds);
      const start = { scale: scaleRef.current, tx: txRef.current, ty: tyRef.current };
      const t0 = performance.now();
      const duration = SEAT_CONFIG.interaction.drillAnimationMs;
      const tick = (now: number) => {
        const u = Math.min(1, (now - t0) / duration);
        const e = 1 - Math.pow(1 - u, 3);
        setScale(start.scale + (target.scale - start.scale) * e);
        setTx(start.tx + (target.tx - start.tx) * e);
        setTy(start.ty + (target.ty - start.ty) * e);
        if (u < 1) drillAnim.current = requestAnimationFrame(tick);
        else drillAnim.current = null;
      };
      drillAnim.current = requestAnimationFrame(tick);
    },
    [computeFit]
  );

  const fitToViewport = useCallback(() => {
    const bounds = drillStack.length
      ? sectionIndex.get(drillStack[drillStack.length - 1])?.section.bounds ?? {
          x: 0,
          y: 0,
          width: venue.width,
          height: venue.height,
        }
      : { x: 0, y: 0, width: venue.width, height: venue.height };
    const fit = computeFit(bounds);
    setScale(fit.scale);
    setTx(fit.tx);
    setTy(fit.ty);
  }, [computeFit, drillStack, sectionIndex, venue.width, venue.height]);

  useEffect(() => {
    fitToViewport();
    const onResize = () => fitToViewport();
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const localToCanvas = useCallback(
    (clientX: number, clientY: number) => {
      const rect = viewportRef.current?.getBoundingClientRect();
      if (!rect) return { x: 0, y: 0 };
      return {
        x: (clientX - rect.left - txRef.current) / scaleRef.current,
        y: (clientY - rect.top - tyRef.current) / scaleRef.current,
      };
    },
    []
  );

  // ─── Flat visibleSeats for marquee hit-test ──────────────────────
  const visibleSeats = useMemo(() => {
    const list: Array<{ seat: AnySeat; section: AnySection }> = [];
    for (const section of visibleSections) {
      if (section.children && section.children.length) continue;
      if (!section.seats) continue;
      for (const seat of section.seats) list.push({ seat, section });
    }
    return list;
  }, [visibleSections]);

  const resolveSeatInfo = useCallback(
    (seatId: string): SeatInfo | null => {
      const entry = seatIndex.get(seatId);
      if (!entry) return null;
      const state = (seatStates[entry.seat.id] ?? entry.seat.state) as SeatState;
      return {
        id: entry.seat.id,
        label: entry.seat.customLabel || entry.seat.label,
        rowLabel: entry.seat.rowLabel,
        seatNumber: entry.seat.seatNumber,
        sectionId: entry.section.id,
        sectionName: entry.section.name,
        sectionPath: [...entry.parents, entry.section.id],
        price: entry.section.price,
        currency: entry.section.currency,
        state,
        accessible: entry.seat.accessible,
      };
    },
    [seatIndex, seatStates]
  );

  const updateSelection = useCallback(
    (next: string[]) => {
      setSelected(next);
      onSelectionChange?.(next);
    },
    [onSelectionChange]
  );

  const drillInto = useCallback(
    (sectionId: string) => {
      const entry = sectionIndex.get(sectionId);
      if (!entry || !entry.section.children || !entry.section.children.length) return;
      const nextStack = [...entry.parents, sectionId];
      setDrillStack(nextStack);
      animateToBounds(entry.section.bounds);
      updateSelection([]);
      onDrillIn?.(sectionId);
    },
    [sectionIndex, animateToBounds, updateSelection, onDrillIn]
  );

  const drillUp = useCallback(() => {
    if (!drillStack.length) return;
    const next = drillStack.slice(0, -1);
    setDrillStack(next);
    updateSelection([]);
    if (next.length) {
      const parent = sectionIndex.get(next[next.length - 1])?.section;
      if (parent) animateToBounds(parent.bounds);
    } else {
      animateToBounds({ x: 0, y: 0, width: venue.width, height: venue.height });
    }
    onDrillOut?.();
  }, [
    drillStack,
    sectionIndex,
    animateToBounds,
    updateSelection,
    onDrillOut,
    venue.width,
    venue.height,
  ]);

  const drillToRoot = useCallback(() => {
    setDrillStack([]);
    updateSelection([]);
    animateToBounds({ x: 0, y: 0, width: venue.width, height: venue.height });
  }, [animateToBounds, updateSelection, venue.width, venue.height]);

  // ─── Viewport culling ───────────────────────────────────────────
  const currentViewportRect = useMemo<Rect>(() => {
    if (!containerSize.width || !containerSize.height) {
      return {
        x: -Infinity,
        y: -Infinity,
        width: Number.POSITIVE_INFINITY,
        height: Number.POSITIVE_INFINITY,
      };
    }
    const invScale = 1 / scale;
    return {
      x: -tx * invScale,
      y: -ty * invScale,
      width: containerSize.width * invScale,
      height: containerSize.height * invScale,
    };
  }, [tx, ty, scale, containerSize.width, containerSize.height]);

  const expandRect = useCallback((r: Rect): Rect => {
    if (!Number.isFinite(r.width) || !Number.isFinite(r.height)) return r;
    const ex = r.width * CULL_EXPAND_FRACTION;
    const ey = r.height * CULL_EXPAND_FRACTION;
    return {
      x: r.x - ex,
      y: r.y - ey,
      width: r.width + ex * 2,
      height: r.height + ey * 2,
    };
  }, []);

  const [committedCullRect, setCommittedCullRect] = useState<Rect>(() =>
    expandRect(currentViewportRect)
  );

  useLayoutEffect(() => {
    const cur = currentViewportRect;
    if (!Number.isFinite(cur.width) || !Number.isFinite(cur.height)) return;
    const cached = committedCullRect;
    if (!Number.isFinite(cached.width) || !Number.isFinite(cached.height)) {
      setCommittedCullRect(expandRect(cur));
      return;
    }
    const marginX = cached.width * CULL_HYSTERESIS_FRACTION;
    const marginY = cached.height * CULL_HYSTERESIS_FRACTION;
    const stillInside =
      cur.x >= cached.x + marginX &&
      cur.y >= cached.y + marginY &&
      cur.x + cur.width <= cached.x + cached.width - marginX &&
      cur.y + cur.height <= cached.y + cached.height - marginY;
    if (!stillInside) {
      setCommittedCullRect(expandRect(cur));
    }
  }, [currentViewportRect, committedCullRect, expandRect]);

  // ─── Render mode (hysteresis on effective seat size) ────────────
  const [renderMode, setRenderMode] = useState<RenderMode>('canvas');
  const effectiveSeatPx = medianSeatSize * scale;
  useLayoutEffect(() => {
    setRenderMode((prev) => {
      if (effectiveSeatPx >= DOM_ZOOM_IN_PX) return 'dom';
      if (effectiveSeatPx < DOM_ZOOM_OUT_PX) return 'canvas';
      return prev;
    });
  }, [effectiveSeatPx]);

  // Also expose a ref — imperative canvas code reads it without React state deps.
  const renderModeRef = useRef<RenderMode>(renderMode);
  renderModeRef.current = renderMode;

  // ─── Culled seat data (for DOM mode rendering) ──────────────────
  const sectionCullData = useMemo(() => {
    const map = new Map<string, { visible: boolean; seats: AnySeat[] }>();
    const cullRect = committedCullRect;
    const cx1 = cullRect.x;
    const cy1 = cullRect.y;
    const cx2 = cullRect.x + cullRect.width;
    const cy2 = cullRect.y + cullRect.height;
    for (const section of sortedVisibleSections) {
      const sb = section.bounds;
      const sectionVisible =
        sb.x < cx2 && sb.x + sb.width > cx1 && sb.y < cy2 && sb.y + sb.height > cy1;
      if (!sectionVisible) {
        map.set(section.id, { visible: false, seats: EMPTY_SEATS });
        continue;
      }
      const isContainer = section.children && section.children.length > 0;
      if (isContainer || !section.seats || !section.seats.length) {
        map.set(section.id, { visible: true, seats: EMPTY_SEATS });
        continue;
      }
      // Canvas mode doesn't need DOM seats — skip per-seat filtering entirely.
      if (renderMode === 'canvas') {
        map.set(section.id, { visible: true, seats: EMPTY_SEATS });
        continue;
      }
      if (section.rotation) {
        map.set(section.id, { visible: true, seats: section.seats });
        continue;
      }
      const sectionFullyInside =
        sb.x >= cx1 && sb.y >= cy1 && sb.x + sb.width <= cx2 && sb.y + sb.height <= cy2;
      if (sectionFullyInside) {
        map.set(section.id, { visible: true, seats: section.seats });
        continue;
      }
      const grid = sectionGrids.get(section.id);
      if (!grid) {
        map.set(section.id, { visible: true, seats: section.seats });
        continue;
      }
      const collected: SeatRef[] = [];
      grid.queryRect(cullRect, collected);
      const filtered: AnySeat[] = new Array(collected.length);
      for (let i = 0; i < collected.length; i++) filtered[i] = collected[i].seat;
      map.set(section.id, { visible: true, seats: filtered });
    }
    return map;
  }, [sortedVisibleSections, committedCullRect, sectionGrids, renderMode]);

  // ─── Canvas base draw (seats as sprites) ────────────────────────
  const drawBase = useCallback(() => {
    const canvas = baseCanvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;
    const w = canvas.width;
    const h = canvas.height;
    const dpr = window.devicePixelRatio || 1;
    ctx.save();
    ctx.setTransform(1, 0, 0, 1, 0, 0);
    ctx.clearRect(0, 0, w, h);
    if (renderModeRef.current !== 'canvas' || w === 0 || h === 0) {
      ctx.restore();
      return;
    }
    ctx.setTransform(
      scaleRef.current * dpr,
      0,
      0,
      scaleRef.current * dpr,
      txRef.current * dpr,
      tyRef.current * dpr
    );

    const cullRect = committedCullRect;
    const selSet = selectedSet;
    const stateMap = seatStates;
    const colors = SEAT_CONFIG.colors;

    // Group by color for batched fills. Typical set: available/reserved/disabled/selected.
    const bucketAvail: SeatRef[] = [];
    const bucketReserved: SeatRef[] = [];
    const bucketDisabled: SeatRef[] = [];
    const bucketSelected: SeatRef[] = [];
    const accessibleSeats: SeatRef[] = [];

    for (let i = 0; i < sortedVisibleSections.length; i++) {
      const section = sortedVisibleSections[i];
      if (section.children && section.children.length) continue;
      const sb = section.bounds;
      if (
        sb.x + sb.width < cullRect.x ||
        sb.x > cullRect.x + cullRect.width ||
        sb.y + sb.height < cullRect.y ||
        sb.y > cullRect.y + cullRect.height
      )
        continue;
      const grid = sectionGrids.get(section.id);
      if (!grid) continue;
      const refs: SeatRef[] = [];
      grid.queryRect(cullRect, refs);
      for (let k = 0; k < refs.length; k++) {
        const r = refs[k];
        if (selSet.has(r.seat.id)) {
          bucketSelected.push(r);
        } else {
          const st = (stateMap[r.seat.id] ?? r.seat.state) as SeatState;
          if (st === 'reserved') bucketReserved.push(r);
          else if (st === 'disabled') bucketDisabled.push(r);
          else bucketAvail.push(r);
        }
        if (r.seat.accessible) accessibleSeats.push(r);
      }
    }

    const drawBucket = (bucket: SeatRef[], fill: string) => {
      if (bucket.length === 0) return;
      ctx.fillStyle = fill;
      ctx.beginPath();
      for (let i = 0; i < bucket.length; i++) {
        const r = bucket[i];
        ctx.rect(r.worldX, r.worldY, r.width, r.height);
      }
      ctx.fill();
    };

    drawBucket(bucketAvail, colors.available);
    drawBucket(bucketReserved, colors.reserved);
    drawBucket(bucketDisabled, colors.disabled);
    drawBucket(bucketSelected, colors.selected);

    if (accessibleSeats.length) {
      ctx.fillStyle = colors.accessibility;
      ctx.beginPath();
      for (let i = 0; i < accessibleSeats.length; i++) {
        const r = accessibleSeats[i];
        const rad = Math.max(1, Math.min(r.width, r.height) * 0.18);
        ctx.moveTo(r.worldX + r.width + rad, r.worldY);
        ctx.arc(r.worldX + r.width, r.worldY, rad, 0, Math.PI * 2);
      }
      ctx.fill();
    }

    ctx.restore();
  }, [committedCullRect, sortedVisibleSections, sectionGrids, seatStates, selectedSet]);

  // ─── Canvas overlay draw (hover outline + marquee rect) ─────────
  const hoveredSeatRef = useRef<string | null>(null);

  const drawOverlay = useCallback(() => {
    const canvas = overlayCanvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;
    const w = canvas.width;
    const h = canvas.height;
    const dpr = window.devicePixelRatio || 1;
    ctx.save();
    ctx.setTransform(1, 0, 0, 1, 0, 0);
    ctx.clearRect(0, 0, w, h);
    if (renderModeRef.current !== 'canvas' || w === 0 || h === 0) {
      ctx.restore();
      return;
    }
    ctx.setTransform(
      scaleRef.current * dpr,
      0,
      0,
      scaleRef.current * dpr,
      txRef.current * dpr,
      tyRef.current * dpr
    );

    const lineWidth = Math.max(1, 2 / scaleRef.current);
    const hovered = hoveredSeatRef.current;
    if (hovered && SEAT_CONFIG.interaction.hoverOutline) {
      const entry = seatIndex.get(hovered);
      if (entry) {
        const wx = entry.section.bounds.x + entry.seat.bounds.x;
        const wy = entry.section.bounds.y + entry.seat.bounds.y;
        ctx.strokeStyle = SEAT_CONFIG.colors.available;
        ctx.lineWidth = lineWidth;
        ctx.strokeRect(
          wx - 1,
          wy - 1,
          entry.seat.bounds.width + 2,
          entry.seat.bounds.height + 2
        );
      }
    }

    ctx.restore();
  }, [seatIndex]);

  // ─── Canvas resize to container × DPR ───────────────────────────
  useLayoutEffect(() => {
    const base = baseCanvasRef.current;
    const overlay = overlayCanvasRef.current;
    if (!base || !overlay) return;
    const dpr = window.devicePixelRatio || 1;
    const w = Math.max(1, Math.floor(containerSize.width * dpr));
    const h = Math.max(1, Math.floor(containerSize.height * dpr));
    if (base.width !== w) base.width = w;
    if (base.height !== h) base.height = h;
    if (overlay.width !== w) overlay.width = w;
    if (overlay.height !== h) overlay.height = h;
  }, [containerSize.width, containerSize.height]);

  // Base redraws when anything visible-seat related changes.
  useEffect(() => {
    drawBase();
  }, [drawBase, scale, tx, ty, renderMode]);

  // Overlay redraws when selection/hover changes or transform moves.
  useEffect(() => {
    drawOverlay();
  }, [drawOverlay, scale, tx, ty, renderMode, selectedSet]);

  // ─── Selection → data-selected mutation (DOM mode only) ─────────
  // React.memo on SeatNode already restricts re-renders to changed seats,
  // but we use getElementById for marquee-size selection deltas to avoid
  // re-running memoized children in the SectionRender boundary.
  const prevSelectedRef = useRef<Set<string>>(new Set());
  useEffect(() => {
    if (renderMode !== 'dom') {
      prevSelectedRef.current = new Set(selectedSet);
      return;
    }
    const prev = prevSelectedRef.current;
    const root = viewportRef.current;
    if (!root) {
      prevSelectedRef.current = new Set(selectedSet);
      return;
    }
    // Removed
    prev.forEach((id) => {
      if (!selectedSet.has(id)) {
        const el = root.querySelector(
          `[data-seat-id="${CSS && CSS.escape ? CSS.escape(id) : id}"]`
        ) as HTMLElement | null;
        if (el) {
          el.dataset.selected = '0';
          el.setAttribute('aria-pressed', 'false');
        }
      }
    });
    // Added
    selectedSet.forEach((id) => {
      if (!prev.has(id)) {
        const el = root.querySelector(
          `[data-seat-id="${CSS && CSS.escape ? CSS.escape(id) : id}"]`
        ) as HTMLElement | null;
        if (el) {
          el.dataset.selected = '1';
          el.setAttribute('aria-pressed', 'true');
        }
      }
    });
    prevSelectedRef.current = new Set(selectedSet);
  }, [selectedSet, renderMode]);

  // ─── Root event delegation (pointer + click + keyboard) ─────────
  const sectionClickRef = useRef<(s: AnySection, e: { shiftKey?: boolean }) => void>(() => {});
  sectionClickRef.current = (section: AnySection, _e: { shiftKey?: boolean }) => {
    const container = section.children && section.children.length;
    const interactions = section.interactions || {};
    const action =
      interactions.clickAction ||
      (container ? SEAT_CONFIG.interaction.defaultContainerClick : 'select');
    if (action === 'drillIn' && container) {
      drillInto(section.id);
    } else if (action === 'url' && interactions.url) {
      window.open(interactions.url, '_blank', 'noopener,noreferrer');
    } else if (action === 'event' && interactions.eventName) {
      viewportRef.current?.dispatchEvent(
        new CustomEvent(interactions.eventName, {
          detail: { sectionId: section.id, sectionName: section.name },
          bubbles: true,
        })
      );
    }
  };

  const toggleSeatRef = useRef<(seatId: string, opts: { additive: boolean }) => void>(() => {});
  toggleSeatRef.current = (seatId: string, opts: { additive: boolean }) => {
    if (readOnly) return;
    const info = resolveSeatInfo(seatId);
    if (!info) return;
    if (info.state === 'reserved' || info.state === 'disabled') return;
    setSelected((prev) => {
      let next: string[];
      if (prev.includes(seatId)) {
        next = prev.filter((id) => id !== seatId);
      } else if (opts.additive) {
        next = [...prev, seatId];
      } else {
        next = [seatId];
      }
      if (next.length > maxSelectable) next = next.slice(-maxSelectable);
      onSelectionChange?.(next);
      onSeatSelect?.(seatId, { ...info, state: 'available' });
      return next;
    });
  };

  // Hit-test seat at world coords using the spatial grid.
  const hitTestSeat = useCallback(
    (wx: number, wy: number): SeatRef | null => {
      for (let i = sortedVisibleSections.length - 1; i >= 0; i--) {
        const section = sortedVisibleSections[i];
        if (section.children && section.children.length) continue;
        const b = section.bounds;
        if (wx < b.x || wx > b.x + b.width || wy < b.y || wy > b.y + b.height) continue;
        const grid = sectionGrids.get(section.id);
        if (!grid) continue;
        const r = grid.queryPoint(wx, wy);
        if (r) return r;
      }
      return null;
    },
    [sortedVisibleSections, sectionGrids]
  );

  const findSectionFromEvent = useCallback(
    (target: EventTarget | null): AnySection | null => {
      if (!(target instanceof HTMLElement) && !(target instanceof SVGElement)) return null;
      const el = (target as Element).closest('[data-section-id]');
      if (!(el instanceof HTMLElement)) return null;
      const id = el.dataset.sectionId;
      if (!id) return null;
      return sectionIndex.get(id)?.section ?? null;
    },
    [sectionIndex]
  );

  // ─── Wheel zoom (rAF-coalesced) ──────────────────────────────────
  useEffect(() => {
    const el = viewportRef.current;
    if (!el) return;
    let pendingDelta = 0;
    let pendingX = 0;
    let pendingY = 0;
    let rafId: number | null = null;

    const flush = () => {
      rafId = null;
      if (pendingDelta === 0) return;
      const factor = Math.exp(-pendingDelta * SEAT_CONFIG.interaction.wheelZoomSpeed);
      const mx = pendingX;
      const my = pendingY;
      pendingDelta = 0;
      setScale((prev) => {
        const next = Math.max(
          SEAT_CONFIG.interaction.minZoom,
          Math.min(SEAT_CONFIG.interaction.maxZoom, prev * factor)
        );
        const ratio = next / prev;
        setTx((prevTx) => mx - (mx - prevTx) * ratio);
        setTy((prevTy) => my - (my - prevTy) * ratio);
        return next;
      });
    };

    const onWheel = (e: WheelEvent) => {
      e.preventDefault();
      const rect = el.getBoundingClientRect();
      pendingDelta += e.deltaY;
      pendingX = e.clientX - rect.left;
      pendingY = e.clientY - rect.top;
      if (rafId == null) rafId = requestAnimationFrame(flush);
    };
    el.addEventListener('wheel', onWheel, { passive: false });
    return () => {
      el.removeEventListener('wheel', onWheel);
      if (rafId != null) cancelAnimationFrame(rafId);
    };
  }, []);

  // ─── Pointer handling (mousedown: pan / marquee start) ──────────
  const handleMouseDown = (e: React.MouseEvent) => {
    const isPanButton = e.button === 1 || e.button === 2;
    if (isPanButton) {
      e.preventDefault();
      panState.current = { startX: e.clientX, startY: e.clientY, tx, ty };
      return;
    }
    if (e.button !== 0) return;

    const target = e.target as HTMLElement;
    const seatEl = target.closest('[data-seat-id]') as HTMLElement | null;
    if (seatEl) {
      // Seat click is handled by onClick (after mouseup). Don't start marquee.
      return;
    }
    const section = findSectionFromEvent(target);
    if (section) {
      const isClickable =
        (section.children && section.children.length) ||
        section.interactions?.clickAction === 'url' ||
        section.interactions?.clickAction === 'event';
      if (isClickable) return;
    }

    // Empty space — start marquee (or clear selection).
    if (SEAT_CONFIG.interaction.marqueeSelect && !readOnly) {
      const { x, y } = localToCanvas(e.clientX, e.clientY);
      if (!e.shiftKey) updateSelection([]);
      marqueeRef.current = true;
      marqueeStartedFromEmpty.current = true;
      setMarquee({ x1: x, y1: y, x2: x, y2: y });
    } else if (!e.shiftKey) {
      updateSelection([]);
    }
  };

  // Click delegation at the root (runs after a mousedown/mouseup with minimal drag).
  const handleClick = (e: React.MouseEvent) => {
    if (marqueeStartedFromEmpty.current) {
      marqueeStartedFromEmpty.current = false;
      return;
    }
    const target = e.target as HTMLElement;
    // 1. DOM seat hit
    const seatEl = target.closest('[data-seat-id]') as HTMLElement | null;
    if (seatEl && seatEl.dataset.interactable === '1') {
      const id = seatEl.dataset.seatId!;
      toggleSeatRef.current(id, {
        additive: e.shiftKey && SEAT_CONFIG.interaction.shiftMultiSelect,
      });
      return;
    }
    // 2. Canvas-mode grid hit
    if (renderModeRef.current === 'canvas') {
      const { x, y } = localToCanvas(e.clientX, e.clientY);
      const ref = hitTestSeat(x, y);
      if (ref) {
        toggleSeatRef.current(ref.seat.id, {
          additive: e.shiftKey && SEAT_CONFIG.interaction.shiftMultiSelect,
        });
        return;
      }
    }
    // 3. Section click
    const section = findSectionFromEvent(target);
    if (section) {
      sectionClickRef.current(section, e);
    }
  };

  // Hover tracking (canvas mode: grid query; DOM mode: CSS :hover does it all).
  useEffect(() => {
    const el = viewportRef.current;
    if (!el) return;
    let rafId: number | null = null;
    let lastX = 0;
    let lastY = 0;
    const flush = () => {
      rafId = null;
      if (renderModeRef.current !== 'canvas') {
        if (hoveredSeatRef.current != null) {
          hoveredSeatRef.current = null;
          drawOverlay();
        }
        return;
      }
      const { x, y } = localToCanvas(lastX, lastY);
      const ref = hitTestSeat(x, y);
      const nextId = ref ? ref.seat.id : null;
      if (nextId !== hoveredSeatRef.current) {
        hoveredSeatRef.current = nextId;
        drawOverlay();
      }
    };
    const onMove = (e: MouseEvent) => {
      lastX = e.clientX;
      lastY = e.clientY;
      if (rafId == null) rafId = requestAnimationFrame(flush);
    };
    const onLeave = () => {
      if (hoveredSeatRef.current != null) {
        hoveredSeatRef.current = null;
        drawOverlay();
      }
    };
    el.addEventListener('mousemove', onMove);
    el.addEventListener('mouseleave', onLeave);
    return () => {
      el.removeEventListener('mousemove', onMove);
      el.removeEventListener('mouseleave', onLeave);
      if (rafId != null) cancelAnimationFrame(rafId);
    };
  }, [localToCanvas, hitTestSeat, drawOverlay]);

  // Global mousemove (rAF-coalesced) for pan + marquee drag.
  useEffect(() => {
    let pendingMove: { clientX: number; clientY: number } | null = null;
    let rafId: number | null = null;

    const flushMove = () => {
      rafId = null;
      if (!pendingMove) return;
      const { clientX, clientY } = pendingMove;
      pendingMove = null;
      if (panState.current) {
        setTx(panState.current.tx + (clientX - panState.current.startX));
        setTy(panState.current.ty + (clientY - panState.current.startY));
      } else if (marqueeRef.current) {
        const { x, y } = localToCanvas(clientX, clientY);
        setMarquee((m) => (m ? { ...m, x2: x, y2: y } : m));
      }
    };

    const onMove = (e: MouseEvent) => {
      pendingMove = { clientX: e.clientX, clientY: e.clientY };
      if (rafId == null) rafId = requestAnimationFrame(flushMove);
    };
    const onUp = () => {
      panState.current = null;
      if (marqueeRef.current) {
        marqueeRef.current = false;
        setMarquee((m) => {
          if (!m) return m;
          const minX = Math.min(m.x1, m.x2);
          const maxX = Math.max(m.x1, m.x2);
          const minY = Math.min(m.y1, m.y2);
          const maxY = Math.max(m.y1, m.y2);
          if (maxX - minX > 3 && maxY - minY > 3) {
            const inBox: string[] = [];
            const marqueeRect: Rect = {
              x: minX,
              y: minY,
              width: maxX - minX,
              height: maxY - minY,
            };
            for (const section of visibleSections) {
              if (section.children && section.children.length) continue;
              const grid = sectionGrids.get(section.id);
              if (!grid) continue;
              const refs: SeatRef[] = [];
              grid.queryRect(marqueeRect, refs);
              for (const r of refs) {
                const sx = r.worldX + r.width / 2;
                const sy = r.worldY + r.height / 2;
                if (sx < minX || sx > maxX || sy < minY || sy > maxY) continue;
                const state = (seatStates[r.seat.id] ?? r.seat.state) as SeatState;
                if (state !== 'available') continue;
                inBox.push(r.seat.id);
              }
            }
            setSelected((prev) => {
              const prevSet = new Set(prev);
              for (const id of inBox) prevSet.add(id);
              const combined = Array.from(prevSet);
              const capped =
                combined.length > maxSelectable ? combined.slice(0, maxSelectable) : combined;
              onSelectionChange?.(capped);
              return capped;
            });
          } else {
            marqueeStartedFromEmpty.current = false;
          }
          return null;
        });
      }
    };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
    return () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
      if (rafId != null) cancelAnimationFrame(rafId);
    };
  }, [
    visibleSections,
    sectionGrids,
    seatStates,
    maxSelectable,
    onSelectionChange,
    localToCanvas,
  ]);

  const handleContextMenu = (e: React.MouseEvent) => e.preventDefault();

  // ─── Keyboard (Enter / Space / Escape / Arrows) ─────────────────
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Escape') {
        if (selected.length) {
          updateSelection([]);
          return;
        }
        if (SEAT_CONFIG.interaction.allowEscapeToDrillUp && drillStack.length) {
          drillUp();
        }
        return;
      }
      const active = document.activeElement as HTMLElement | null;
      const isSeat = !!active && active.dataset.seatId;
      if (isSeat && (e.key === 'Enter' || e.key === ' ')) {
        if (active.dataset.interactable === '1') {
          e.preventDefault();
          toggleSeatRef.current(active.dataset.seatId!, {
            additive: e.shiftKey && SEAT_CONFIG.interaction.shiftMultiSelect,
          });
        }
        return;
      }
      if (!['ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown'].includes(e.key)) return;
      if (!isSeat) return;
      e.preventDefault();

      const seats = Array.from(
        viewportRef.current?.querySelectorAll<HTMLElement>(
          '[data-seat-id][data-interactable="1"]'
        ) ?? []
      );
      const currentRect = active.getBoundingClientRect();
      const cx = currentRect.left + currentRect.width / 2;
      const cy = currentRect.top + currentRect.height / 2;

      let best: { el: HTMLElement; score: number } | null = null;
      for (const el of seats) {
        if (el === active) continue;
        const r = el.getBoundingClientRect();
        const dx = r.left + r.width / 2 - cx;
        const dy = r.top + r.height / 2 - cy;
        let aligned = false;
        if (e.key === 'ArrowRight') aligned = dx > 0 && Math.abs(dy) <= Math.abs(dx);
        if (e.key === 'ArrowLeft') aligned = dx < 0 && Math.abs(dy) <= Math.abs(dx);
        if (e.key === 'ArrowDown') aligned = dy > 0 && Math.abs(dx) <= Math.abs(dy);
        if (e.key === 'ArrowUp') aligned = dy < 0 && Math.abs(dx) <= Math.abs(dy);
        if (!aligned) continue;
        const score = dx * dx + dy * dy;
        if (!best || score < best.score) best = { el, score };
      }
      if (best) best.el.focus();
    },
    [updateSelection, drillStack, drillUp, selected.length]
  );

  // ─── Derived UI ──────────────────────────────────────────────────
  const marqueeStyle: React.CSSProperties | null = marquee
    ? {
        position: 'absolute',
        left: Math.min(marquee.x1, marquee.x2),
        top: Math.min(marquee.y1, marquee.y2),
        width: Math.abs(marquee.x2 - marquee.x1),
        height: Math.abs(marquee.y2 - marquee.y1),
        border: `1.5px dashed ${SEAT_CONFIG.colors.marqueeStroke}`,
        background: SEAT_CONFIG.colors.marqueeFill,
        pointerEvents: 'none',
      }
    : null;

  const breadcrumbSections = useMemo(
    () => drillStack.map((id) => sectionIndex.get(id)?.section).filter(Boolean) as AnySection[],
    [drillStack, sectionIndex]
  );

  const rootStyle: React.CSSProperties = {
    position: 'relative',
    width: '100%',
    height: '100%',
    minHeight: 400,
    overflow: 'hidden',
    background: SEAT_CONFIG.colors.background,
    borderRadius: 8,
    cursor: panState.current ? 'grabbing' : 'default',
    userSelect: 'none',
    ...style,
  };

  const zoomIn = useCallback(
    () =>
      setScale((s) => Math.min(SEAT_CONFIG.interaction.maxZoom, s + SEAT_CONFIG.interaction.zoomStep)),
    []
  );
  const zoomOut = useCallback(
    () =>
      setScale((s) => Math.max(SEAT_CONFIG.interaction.minZoom, s - SEAT_CONFIG.interaction.zoomStep)),
    []
  );

  const transformedStyle: React.CSSProperties = {
    position: 'absolute',
    left: 0,
    top: 0,
    width: venue.width,
    height: venue.height,
    transform: `translate3d(${tx}px, ${ty}px, 0) scale(${scale})`,
    transformOrigin: '0 0',
    willChange: 'transform',
    backfaceVisibility: 'hidden',
  };

  const canvasBaseStyle: React.CSSProperties = {
    ...CANVAS_LAYER_STYLE,
    display: renderMode === 'canvas' ? 'block' : 'none',
    zIndex: 1,
  };
  const canvasOverlayStyle: React.CSSProperties = {
    ...CANVAS_LAYER_STYLE,
    display: renderMode === 'canvas' ? 'block' : 'none',
    zIndex: 2,
  };

  return (
    <div
      ref={viewportRef}
      className={className}
      style={rootStyle}
      onMouseDown={handleMouseDown}
      onClick={handleClick}
      onContextMenu={handleContextMenu}
      onKeyDown={handleKeyDown}
      tabIndex={0}
      role="application"
      aria-label={`Seat map for ${venue.name}`}
      data-render-mode={renderMode}
      data-seat-px={effectiveSeatPx.toFixed(1)}
    >
      <RuntimeStyles />
      <SymbolDefs />

      <div style={transformedStyle}>
        {stage && !drillStack.length && (
          <div
            style={{
              position: 'absolute',
              left: stage.bounds.x,
              top: stage.bounds.y,
              width: stage.bounds.width,
              height: stage.bounds.height,
              background: stage.fill,
              color: 'rgba(255,255,255,0.85)',
              borderRadius: 8,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontWeight: 700,
              letterSpacing: 4,
              fontSize: 14,
            }}
          >
            {stage.label || 'STAGE'}
          </div>
        )}

        {sortedVisibleSections.map((section: AnySection) => {
          const cull = sectionCullData.get(section.id);
          if (!cull || !cull.visible) return null;
          return (
            <SectionRender
              key={section.id}
              section={section}
              seatsToRender={cull.seats}
              selectedSet={selectedSet}
              seatStates={seatStates}
            />
          );
        })}

        {marqueeStyle && <div style={marqueeStyle} />}
      </div>

      <canvas ref={baseCanvasRef} style={canvasBaseStyle} aria-hidden="true" />
      <canvas ref={overlayCanvasRef} style={canvasOverlayStyle} aria-hidden="true" />

      {SEAT_CONFIG.interaction.showBreadcrumb && drillStack.length > 0 && (
        <Breadcrumb
          venueName={venue.name}
          sections={breadcrumbSections}
          onRoot={drillToRoot}
          onUp={drillUp}
        />
      )}

      <Controls onZoomIn={zoomIn} onZoomOut={zoomOut} onFit={fitToViewport} zoom={scale} />

      <Legend selectedCount={selected.length} maxSelectable={maxSelectable} />
    </div>
  );
}

// ─── INLINE VENUE DATA ────────────────────────────────────────────
